// Parse y validar payload de CulqiLink webhook
// Soporta charge.creation.succeeded (tarjeta/Yape) y order.status.changed (billeteras)
const body = $json.body || $json;
const headers = $json.headers || {};

// Normalizar: CulqiLink puede enviar datos en body directo o dentro de body.object
const data = body.object || body;

// Paquetes por description (titulo del CulqiLink) — resuelve precios repetidos
const PACKAGES = {
  'resummo select':       { slug: 'select',       name: 'Resummo SELECT',       notionPage: '2ee28574-650f-80c4-bdc2-f043e19f4f0b', anki: false },
  'resummo basicas':      { slug: 'basicas',      name: 'Resummo BASICAS',      notionPage: '2ee28574-650f-80c4-bdc2-f043e19f4f0b', anki: false },
  'resummo core':         { slug: 'core',         name: 'Resummo CORE',         notionPage: '2ee28574-650f-80c4-bdc2-f043e19f4f0b', anki: false },
  'resummo core clinicas':{ slug: 'core-clinicas', name: 'Resummo CORE Clinicas',notionPage: '2ee28574-650f-80c4-bdc2-f043e19f4f0b', anki: false },
  'resummo core basicas': { slug: 'core-basicas', name: 'Resummo CORE Basicas', notionPage: '2ee28574-650f-80c4-bdc2-f043e19f4f0b', anki: false },
  'resummo essalud/enam': { slug: 'essalud-enam', name: 'Resummo ESSALUD/ENAM', notionPage: '2f428574-650f-80d3-aafc-cb5374c44e14', anki: false },
  'resummo all access':   { slug: 'all-access',   name: 'Resummo ALL ACCESS',   notionPage: '2ed28574-650f-804e-85ce-ee3fc1bf4631', anki: true },
  'resummo anki':         { slug: 'anki',         name: 'Resummo ANKI',         notionPage: '31e28574-650f-8058-b3f3-e6140913476e', anki: true },
  'resummo encaps':       { slug: 'encaps',       name: 'Resummo ENCAPS',       notionPage: '31e28574-650f-8058-b3f3-e6140913476e', anki: true }
};

// Fallback por monto (solo para precios unicos)
const PACKAGES_BY_AMOUNT = {
  2900:  'resummo select',
  13900: 'resummo essalud/enam',
  15900: 'resummo all access'
};

const DRIVE_LINK = 'https://drive.google.com/drive/folders/1l2NYW_6ICSK1DWwlB3hT7WGW3YAc_J9T';

// Extraer campos normalizados
const rawPayload = JSON.stringify(body, null, 2);
const amount = data.amount || body.amount || 0;
const email = data.email || body.email || data.customer_email || body.metadata?.email || '';
const customerName = data.customer_name || body.metadata?.customer_name || data.antifraud_details?.first_name || '';
const orderId = data.id || body.id || body.order_id || 'unknown_' + Date.now();
const status = data.status || data.state || data.outcome?.type || 'unknown';
const currency = data.currency_code || body.currency_code || 'PEN';
const description = (data.description || body.description || '').toLowerCase().trim();

// Detectar paquete: primero por description, fallback por monto
let pkg = PACKAGES[description];
if (!pkg && PACKAGES_BY_AMOUNT[amount]) {
  pkg = PACKAGES[PACKAGES_BY_AMOUNT[amount]];
}
if (!pkg) {
  pkg = { slug: 'desconocido', name: 'Desconocido (desc: ' + description + ', monto: ' + amount + ')', notionPage: '', anki: false };
}

const fechaPago = $now.toFormat('yyyy-MM-dd HH:mm:ss');

return {
  json: {
    email,
    nombre: customerName,
    paquete: pkg.name,
    paqueteSlug: pkg.slug,
    monto: amount / 100,
    montoRaw: amount,
    orderId,
    status,
    currency,
    fechaPago,
    notionPageId: pkg.notionPage,
    includesAnki: pkg.anki,
    driveLink: pkg.anki ? DRIVE_LINK : '',
    description,
    rawPayload,
    isValid: email !== '' && amount > 0,
    validationErrors: [
      ...(email === '' ? ['Email vacio'] : []),
      ...(amount === 0 ? ['Monto es 0'] : []),
      ...(pkg.slug === 'desconocido' ? ['Paquete no identificado: ' + description + ' / ' + amount] : [])
    ]
  }
};

// Formatear mensaje de venta para Slack con link Notion accionable
const data = $('Parse y Validar').first().json;

// URLs de Notion por paquete (para que Andre/Nair hagan click y compartan)
const NOTION_URLS = {
  'select':       'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'basicas':      'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'core':         'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'core-clinicas':'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'core-basicas': 'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'essalud-enam': 'https://www.notion.so/2f428574650f80d3aafccb5374c44e14',
  'all-access':   'https://www.notion.so/2ed28574650f804e85ceee3fc1bf4631',
  'anki':         'https://www.notion.so/31e28574650f8058b3f3e6140913476e',
  'encaps':       'https://www.notion.so/31e28574650f8058b3f3e6140913476e'
};

const notionUrl = NOTION_URLS[data.paqueteSlug] || '';
const driveLink = data.driveLink || '';

const slackMessage = {
  text: `Nueva venta: ${data.paquete} - ${data.email}`,
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: 'Nueva Venta Resummo',
        emoji: true
      }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Paquete:*\n${data.paquete}` },
        { type: 'mrkdwn', text: `*Monto:*\nS/${data.monto}` },
        { type: 'mrkdwn', text: `*Cliente:*\n${data.nombre || 'No proporcionado'}` },
        { type: 'mrkdwn', text: `*Fecha:*\n${data.fechaPago}` }
      ]
    },
    {
      type: 'divider'
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Email del comprador (copiar):*\n\`${data.email}\``
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Paso 1:* Abrir pagina Notion del paquete:\n<${notionUrl}|Abrir ${data.paquete} en Notion>\n\n*Paso 2:* Click \"Share\" arriba a la derecha → pegar email → invitar como Guest`
      }
    },
    ...(data.includesAnki ? [{
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Paso 3 (Anki):* Compartir carpeta Drive con el mismo email:\n<${driveLink}|Abrir carpeta Anki en Drive>`
      }
    }] : []),
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: `Order: ${data.orderId}` }
      ]
    }
  ]
};

return { json: { slackMessage } };

// Preparar fila para Google Sheets — SOLO campos de Sheets, sin ...data
const data = $('Parse y Validar').first().json;

// Formatear fecha como DD/MM/YYYY
const parts = data.fechaPago.split(' ')[0].split('-');
const fechaFormateada = parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : data.fechaPago;

return {
  json: {
    'INGRESOS': fechaFormateada,
    'col_3': data.nombre || data.email,
    'col_4': data.paquete.toUpperCase(),
    'col_5': 'CULQILINK',
    'col_6': 'ANDRÉ',
    'col_7': data.monto,
    'col_8': data.orderId,
    'col_9': data.email
  }
};
